7	/* Start Composition */
8	class CStartCompositionEditSession : public CEditSession {
9	 public:
10	  CStartCompositionEditSession(com_ptr<WeaselTSF> pTextService,
11	                               com_ptr<ITfContext> pContext,
12	                               BOOL fCUASWorkaroundEnabled,
13	                               BOOL inlinePreeditEnabled)
14	      : CEditSession(pTextService, pContext),
15	        _inlinePreeditEnabled(inlinePreeditEnabled) {
16	    _fCUASWorkaroundEnabled = fCUASWorkaroundEnabled;
17	  }
18	
19	  /* ITfEditSession */
20	  STDMETHODIMP DoEditSession(TfEditCookie ec);
21	
22	 private:
23	  BOOL _fCUASWorkaroundEnabled;
24	  BOOL _inlinePreeditEnabled;
25	};
26	
27	STDAPI CStartCompositionEditSession::DoEditSession(TfEditCookie ec) {
28	  HRESULT hr = E_FAIL;
29	  com_ptr<ITfInsertAtSelection> pInsertAtSelection;
30	  com_ptr<ITfRange> pRangeComposition;
31	  if (_pContext->QueryInterface(IID_ITfInsertAtSelection,
32	                                (LPVOID*)&pInsertAtSelection) != S_OK)
33	    return hr;
34	  if (pInsertAtSelection->InsertTextAtSelection(ec, TF_IAS_QUERYONLY, NULL, 0,
35	                                                &pRangeComposition) != S_OK)
36	    return hr;
37	
38	  com_ptr<ITfContextComposition> pContextComposition;
39	  com_ptr<ITfComposition> pComposition;
40	  if (_pContext->QueryInterface(IID_ITfContextComposition,
41	                                (LPVOID*)&pContextComposition) != S_OK)
42	    return hr;
43	  if ((pContextComposition->StartComposition(
44	           ec, pRangeComposition, _pTextService, &pComposition) == S_OK) &&
45	      (pComposition != NULL)) {
46	    _pTextService->_SetComposition(pComposition);
47	
48	    /* WORKAROUND:
49	     *   CUAS does not provide a correct GetTextExt() position unless the
50	     * composition is filled with characters. So we insert a zero width space
51	     * here. The workaround is only needed when inline preedit is not enabled.
52	     *   See https://github.com/rime/weasel/pull/883#issuecomment-1567625762
53	     */
54	    if (!_inlinePreeditEnabled) {
55	      pRangeComposition->SetText(ec, TF_ST_CORRECTION, L" ", 1);
56	    }
57	
58	    /* set selection */
59	    TF_SELECTION tfSelection;
60	    if (_inlinePreeditEnabled)
61	      pRangeComposition->Collapse(ec, TF_ANCHOR_END);
62	    else
63	      pRangeComposition->Collapse(ec, TF_ANCHOR_START);
64	    tfSelection.range = pRangeComposition;
65	    tfSelection.style.ase = TF_AE_NONE;
66	    tfSelection.style.fInterimChar = FALSE;
67	    _pContext->SetSelection(ec, 1, &tfSelection);
68	  }
69	
70	  return hr;
71	}
