73	void WeaselTSF::_StartComposition(com_ptr<ITfContext> pContext,
74	                                  BOOL fCUASWorkaroundEnabled) {
75	  com_ptr<CStartCompositionEditSession> pStartCompositionEditSession;
76	  pStartCompositionEditSession.Attach(new CStartCompositionEditSession(
77	      this, pContext, fCUASWorkaroundEnabled, _cand->style().inline_preedit));
78	  _cand->StartUI();
79	  if (pStartCompositionEditSession != nullptr) {
80	    HRESULT hr;
81	    pContext->RequestEditSession(_tfClientId, pStartCompositionEditSession,
82	                                 TF_ES_ASYNCDONTCARE | TF_ES_READWRITE, &hr);
83	  }
84	}
