86	/* End Composition */
87	class CEndCompositionEditSession : public CEditSession {
88	 public:
89	  CEndCompositionEditSession(com_ptr<WeaselTSF> pTextService,
90	                             com_ptr<ITfContext> pContext,
91	                             com_ptr<ITfComposition> pComposition,
92	                             BOOL clear = TRUE)
93	      : CEditSession(pTextService, pContext), _clear(clear) {
94	    _pComposition = pComposition;
95	  }
96	
97	  /* ITfEditSession */
98	  STDMETHODIMP DoEditSession(TfEditCookie ec);
99	
100	 private:
101	  com_ptr<ITfComposition> _pComposition;
102	  BOOL _clear;
103	};
