105	STDAPI CEndCompositionEditSession::DoEditSession(TfEditCookie ec) {
106	  /* Clear the dummy text we set before, if any. */
107	  if (_pComposition == nullptr)
108	    return S_OK;
109	  // Avoid null pointer dereference
110	  if (!_pTextService || !_pContext)
111	    return S_OK;
112	
113	  _pTextService->_ClearCompositionDisplayAttributes(ec, _pContext);
114	
115	  com_ptr<ITfRange> pCompositionRange;
116	  if (_clear && _pComposition->GetRange(&pCompositionRange) == S_OK)
117	    pCompositionRange->SetText(ec, 0, L"", 0);
118	
119	  _pComposition->EndComposition(ec);
120	  if (_pTextService)  // if _pTextService released, skip _FinalizeComposition
121	    _pTextService->_FinalizeComposition();
122	  return S_OK;
123	}
