130	  if ((pEditSession = new CEndCompositionEditSession(
131	           this, pContext, _pComposition, clear)) != NULL) {
132	    pContext->RequestEditSession(_tfClientId, pEditSession,
133	                                 TF_ES_ASYNCDONTCARE | TF_ES_READWRITE, &hr);
134	    pEditSession->Release();
135	  }
136	}
