138	/* Get Text Extent */
139	class CGetTextExtentEditSession : public CEditSession {
140	 public:
141	  CGetTextExtentEditSession(com_ptr<WeaselTSF> pTextService,
142	                            com_ptr<ITfContext> pContext,
143	                            com_ptr<ITfContextView> pContextView,
144	                            com_ptr<ITfComposition> pComposition,
145	                            bool enhancedPosition)
146	      : CEditSession(pTextService, pContext) {
147	    _pContextView = pContextView;
148	    _pComposition = pComposition;
149	    _enhancedPosition = enhancedPosition;
150	  }
151	
152	  /* ITfEditSession */
153	  STDMETHODIMP DoEditSession(TfEditCookie ec);
154	
155	 private:
156	  com_ptr<ITfContextView> _pContextView;
157	  com_ptr<ITfComposition> _pComposition;
158	  bool _enhancedPosition;
159	};
160	
161	STDAPI CGetTextExtentEditSession::DoEditSession(TfEditCookie ec) {
162	  com_ptr<ITfInsertAtSelection> pInsertAtSelection;
163	  com_ptr<ITfRange> pRangeComposition;
164	  ITfRange* pRange;
165	  RECT rc;
166	  BOOL fClipped;
167	  TF_SELECTION selection;
168	  ULONG nSelection;
169	
170	  if (FAILED(_pContext->QueryInterface(IID_ITfInsertAtSelection,
171	                                       (LPVOID*)&pInsertAtSelection)))
172	    return E_FAIL;
173	  if (FAILED(_pContext->GetSelection(ec, TF_DEFAULT_SELECTION, 1, &selection,
174	                                     &nSelection)))
175	    return E_FAIL;
176	
177	  if (_pComposition != nullptr && _pComposition->GetRange(&pRange) == S_OK) {
178	    pRange->Collapse(ec, TF_ANCHOR_START);
179	  } else {
180	    // composition end
181	    // note: selection.range is always an empty range
182	    pRange = selection.range;
183	  }
184	
185	  if ((_pContextView->GetTextExt(ec, pRange, &rc, &fClipped)) == S_OK &&
186	      (rc.left != 0 || rc.top != 0)) {
187	    // get the foreground window pos and check if rc from GetTextExt is out of
188	    // window
189	    if (_enhancedPosition) {
190	      HWND hwnd;
191	      RECT rcForegroundWindow;
192	      hwnd = GetForegroundWindow();
193	      ::GetWindowRect(hwnd, &rcForegroundWindow);
194	
195	      if (rc.left < rcForegroundWindow.left ||
196	          rc.left > rcForegroundWindow.right ||
197	          rc.top < rcForegroundWindow.top ||
198	          rc.top > rcForegroundWindow.bottom) {
199	        POINT pt;
200	        bool hasCaret = ::GetCaretPos(&pt);
201	        int offsetx = rcForegroundWindow.left - rc.left + (hasCaret ? pt.x : 0);
202	        int offsety = rcForegroundWindow.top - rc.top + (hasCaret ? pt.y : 0);
203	        rc.left += offsetx;
204	        rc.right += offsetx;
205	        rc.top += offsety;
206	        rc.bottom += offsety;
207	      }
208	    }
209	    _pTextService->_SetCompositionPosition(rc);
210	  }
211	  return S_OK;
212	}
