214	/* Composition Window Handling */
215	BOOL WeaselTSF::_UpdateCompositionWindow(com_ptr<ITfContext> pContext) {
216	  com_ptr<ITfContextView> pContextView;
217	  if (pContext->GetActiveView(&pContextView) != S_OK)
218	    return FALSE;
219	  com_ptr<CGetTextExtentEditSession> pEditSession;
220	  pEditSession.Attach(
221	      new CGetTextExtentEditSession(this, pContext, pContextView, _pComposition,
222	                                    _cand->style().enhanced_position));
223	  if (pEditSession == NULL) {
224	    return FALSE;
225	  }
226	  HRESULT hr;
227	  pContext->RequestEditSession(_tfClientId, pEditSession,
228	                               TF_ES_ASYNCDONTCARE | TF_ES_READ, &hr);
229	  return SUCCEEDED(hr);
230	}
231	
232	void WeaselTSF::_SetCompositionPosition(const RECT& rc) {
233	  /* Test if rect is valid.
234	   * If it is invalid during CUAS test, we need to apply CUAS workaround */
235	  if (!_fCUASWorkaroundTested) {
236	    _fCUASWorkaroundTested = TRUE;
237	    if (rc.top == rc.bottom) {
238	      _fCUASWorkaroundEnabled = TRUE;
239	      return;
240	    }
241	  }
242	  RECT _rc;
243	  _rc.left = _rc.right = rc.left;
244	  _rc.top = _rc.bottom = rc.bottom;
245	  m_client.UpdateInputPosition(rc);
246	  _cand->UpdateInputPosition(rc);
247	}
