249	/* Inline Preedit */
250	class CInlinePreeditEditSession : public CEditSession {
251	 public:
252	  CInlinePreeditEditSession(com_ptr<WeaselTSF> pTextService,
253	                            com_ptr<ITfContext> pContext,
254	                            com_ptr<ITfComposition> pComposition,
255	                            const std::shared_ptr<weasel::Context> context)
256	      : CEditSession(pTextService, pContext),
257	        _pComposition(pComposition),
258	        _context(context) {}
259	
260	  /* ITfEditSession */
261	  STDMETHODIMP DoEditSession(TfEditCookie ec);
262	
263	 private:
264	  com_ptr<ITfComposition> _pComposition;
265	  const std::shared_ptr<weasel::Context> _context;
266	};
267	
268	STDAPI CInlinePreeditEditSession::DoEditSession(TfEditCookie ec) {
269	  std::wstring preedit = _context->preedit.str;
270	
271	  com_ptr<ITfRange> pRangeComposition;
272	  if (_pComposition == nullptr)
273	    return E_FAIL;
274	  if ((_pComposition->GetRange(&pRangeComposition)) != S_OK)
275	    return E_FAIL;
276	
277	  if ((pRangeComposition->SetText(ec, 0, preedit.c_str(),
278	                                  static_cast<LONG>(preedit.length()))) != S_OK)
279	    return E_FAIL;
280	
281	  /* TODO: Check the availability and correctness of these values */
282	  int sel_cursor = -1;
283	  for (size_t i = 0; i < _context->preedit.attributes.size(); i++) {
284	    if (_context->preedit.attributes.at(i).type == weasel::HIGHLIGHTED) {
285	      sel_cursor = _context->preedit.attributes.at(i).range.cursor;
286	      break;
287	    }
288	  }
289	
290	  _pTextService->_SetCompositionDisplayAttributes(ec, _pContext,
291	                                                  pRangeComposition);
292	
293	  /* Set caret */
294	  LONG cch;
295	  TF_SELECTION tfSelection;
296	  if (sel_cursor < 0) {
297	    pRangeComposition->Collapse(ec, TF_ANCHOR_END);
298	  } else {
299	    pRangeComposition->Collapse(ec, TF_ANCHOR_START);
300	    pRangeComposition->ShiftStart(ec, sel_cursor, &cch, NULL);
301	  }
302	  tfSelection.range = pRangeComposition;
303	  tfSelection.style.ase = TF_AE_NONE;
304	  tfSelection.style.fInterimChar = FALSE;
305	  _pContext->SetSelection(ec, 1, &tfSelection);
306	
307	  return S_OK;
308	}
309	
310	BOOL WeaselTSF::_ShowInlinePreedit(
311	    com_ptr<ITfContext> pContext,
312	    const std::shared_ptr<weasel::Context> context) {
313	  com_ptr<CInlinePreeditEditSession> pEditSession;
314	  pEditSession.Attach(
315	      new CInlinePreeditEditSession(this, pContext, _pComposition, context));
316	  if (pEditSession != NULL) {
317	    HRESULT hr;
318	    pContext->RequestEditSession(_tfClientId, pEditSession,
319	                                 TF_ES_ASYNCDONTCARE | TF_ES_READWRITE, &hr);
320	  }
321	  return TRUE;
322	}
