324	/* Update Composition */
325	class CInsertTextEditSession : public CEditSession {
326	 public:
327	  CInsertTextEditSession(com_ptr<WeaselTSF> pTextService,
328	                         com_ptr<ITfContext> pContext,
329	                         com_ptr<ITfComposition> pComposition,
330	                         const std::wstring& text)
331	      : CEditSession(pTextService, pContext),
332	        _text(text),
333	        _pComposition(pComposition) {}
334	
335	  /* ITfEditSession */
336	  STDMETHODIMP DoEditSession(TfEditCookie ec);
337	
338	 private:
339	  std::wstring _text;
340	  com_ptr<ITfComposition> _pComposition;
341	};
342	
343	STDMETHODIMP CInsertTextEditSession::DoEditSession(TfEditCookie ec) {
344	  com_ptr<ITfRange> pRange;
345	  TF_SELECTION tfSelection;
346	  HRESULT hRet = S_OK;
347	
348	  if (_pComposition == nullptr)
349	    return E_FAIL;
350	  if (FAILED(_pComposition->GetRange(&pRange)))
351	    return E_FAIL;
352	
353	  if (FAILED(pRange->SetText(ec, 0, _text.c_str(),
354	                             static_cast<LONG>(_text.length()))))
355	    return E_FAIL;
356	
357	  /* update the selection to an insertion point just past the inserted text. */
358	  pRange->Collapse(ec, TF_ANCHOR_END);
359	
360	  tfSelection.range = pRange;
361	  tfSelection.style.ase = TF_AE_NONE;
362	  tfSelection.style.fInterimChar = FALSE;
363	
364	  _pContext->SetSelection(ec, 1, &tfSelection);
365	
366	  return hRet;
367	}
368	
369	BOOL WeaselTSF::_InsertText(com_ptr<ITfContext> pContext,
370	                            const std::wstring& text) {
371	  CInsertTextEditSession* pEditSession;
372	  HRESULT hr;
373	
374	  if ((pEditSession = new CInsertTextEditSession(this, pContext, _pComposition,
375	                                                 text)) != NULL) {
376	    pContext->RequestEditSession(_tfClientId, pEditSession,
377	                                 TF_ES_ASYNCDONTCARE | TF_ES_READWRITE, &hr);
378	    pEditSession->Release();
379	  }
380	
381	  return TRUE;
382	}
383	
384	void WeaselTSF::_UpdateComposition(com_ptr<ITfContext> pContext) {
385	  HRESULT hr;
386	
387	  _pEditSessionContext = pContext;
388	
389	  _pEditSessionContext->RequestEditSession(
390	      _tfClientId, this, TF_ES_ASYNCDONTCARE | TF_ES_READWRITE, &hr);
391	  _async_edit = !!(hr == TF_S_ASYNC);
392	  _UpdateCompositionWindow(pContext);
393	}
394	
395	/* Composition State */
396	STDAPI WeaselTSF::OnCompositionTerminated(TfEditCookie ecWrite,
397	                                          ITfComposition* pComposition) {
398	  // NOTE:
399	  // This will be called when an edit session ended up with an empty composition
400	  // string, Even if it is closed normally. Silly M$.
401	
402	  _AbortComposition();
403	  return S_OK;
404	}
405	
406	void WeaselTSF::_AbortComposition(bool clear) {
407	  m_client.ClearComposition();
408	  if (_IsComposing()) {
409	    _EndComposition(_pEditSessionContext, clear);
410	  }
411	  _committed = TRUE;
412	  _cand->Destroy();
413	}
414	
415	void WeaselTSF::_FinalizeComposition() {
416	  _pComposition = nullptr;
417	}
418	
419	void WeaselTSF::_SetComposition(com_ptr<ITfComposition> pComposition) {
420	  _pComposition = pComposition;
421	}
422	
423	BOOL WeaselTSF::_IsComposing() {
424	  return _pComposition != NULL;
425	}
