7	static weasel::KeyEvent prevKeyEvent;
8	static BOOL prevfEaten = FALSE;
9	static int keyCountToSimulate = 0;
10	
11	void WeaselTSF::_ProcessKeyEvent(WPARAM wParam, LPARAM lParam, BOOL* pfEaten) {
12	  // when _IsKeyboardDisabled don't eat the key,
13	  // when keyboard closable and keyboard closed, don't eat the key
14	  if ((_isToOpenClose && !_IsKeyboardOpen()) || _IsKeyboardDisabled()) {
15	    *pfEaten = FALSE;
16	    return;
17	  }
18	
19	  // if server connection is Not OK, don't eat it.
20	  if (!_EnsureServerConnected()) {
21	    *pfEaten = FALSE;
22	    return;
23	  }
24	  weasel::KeyEvent ke;
25	  GetKeyboardState(_lpbKeyState);
26	  if (!ConvertKeyEvent(static_cast<UINT>(wParam), lParam, _lpbKeyState, ke)) {
27	    /* Unknown key event */
28	    *pfEaten = FALSE;
29	  } else {
30	    // cheet key code when vertical auto reverse happened, swap up and down
31	    if (_cand->GetIsReposition()) {
32	      if (ke.keycode == ibus::Up)
33	        ke.keycode = ibus::Down;
34	      else if (ke.keycode == ibus::Down)
35	        ke.keycode = ibus::Up;
36	    }
37	    if (!keyCountToSimulate)
38	      *pfEaten = (BOOL)m_client.ProcessKeyEvent(ke);
39	
40	    if (ke.keycode == ibus::Caps_Lock) {
41	      if (prevKeyEvent.keycode == ibus::Caps_Lock && prevfEaten == TRUE &&
42	          (ke.mask & ibus::RELEASE_MASK) && (!keyCountToSimulate)) {
43	        if ((GetKeyState(VK_CAPITAL) & 0x01)) {
44	          if (_committed || (!*pfEaten && _status.composing)) {
45	            keyCountToSimulate = 2;
46	            INPUT inputs[2];
47	            inputs[0].type = INPUT_KEYBOARD;
48	            inputs[0].ki = {VK_CAPITAL, 0, 0, 0, 0};
49	            inputs[1].type = INPUT_KEYBOARD;
50	            inputs[1].ki = {VK_CAPITAL, 0, KEYEVENTF_KEYUP, 0, 0};
51	            ::SendInput(sizeof(inputs) / sizeof(INPUT), inputs, sizeof(INPUT));
52	          }
53	        }
54	        *pfEaten = TRUE;
55	      }
56	      if (keyCountToSimulate)
57	        keyCountToSimulate--;
58	    }
59	
60	    prevfEaten = *pfEaten;
61	    prevKeyEvent = ke;
62	  }
63	}
64	
65	STDAPI WeaselTSF::OnSetFocus(BOOL fForeground) {
66	  if (fForeground)
67	    m_client.FocusIn();
68	  else {
69	    m_client.FocusOut();
70	    _AbortComposition();
71	  }
72	
73	  return S_OK;
74	}
