76	/* Some apps sends strange OnTestKeyDown/OnKeyDown combinations:
77	 *  Some sends OnKeyDown() only. (QQ2012)
78	 *  Some sends multiple OnTestKeyDown() for a single key event. (MS WORD 2010
79	 * x64)
80	 *
81	 * We assume every key event will eventually cause a OnKeyDown() call.
82	 * We use _fTestKeyDownPending to omit multiple OnTestKeyDown() calls,
83	 *  and for OnKeyDown() to check if the key has already been sent to the server.
84	 */
85	
86	STDAPI WeaselTSF::OnTestKeyDown(ITfContext* pContext,
87	                                WPARAM wParam,
88	                                LPARAM lParam,
89	                                BOOL* pfEaten) {
90	  _fTestKeyUpPending = FALSE;
91	  if (_fTestKeyDownPending) {
92	    *pfEaten = TRUE;
93	    return S_OK;
94	  }
95	  _ProcessKeyEvent(wParam, lParam, pfEaten);
96	  _UpdateComposition(pContext);
97	  if (*pfEaten)
98	    _fTestKeyDownPending = TRUE;
99	  return S_OK;
100	}
101	
102	STDAPI WeaselTSF::OnKeyDown(ITfContext* pContext,
103	                            WPARAM wParam,
104	                            LPARAM lParam,
105	                            BOOL* pfEaten) {
106	  _fTestKeyUpPending = FALSE;
107	  if (_fTestKeyDownPending) {
108	    _fTestKeyDownPending = FALSE;
109	    *pfEaten = TRUE;
110	  } else {
111	    _ProcessKeyEvent(wParam, lParam, pfEaten);
112	    _UpdateComposition(pContext);
113	  }
114	  return S_OK;
115	}
