122	  if (_fTestKeyUpPending) {
123	    *pfEaten = TRUE;
124	    return S_OK;
125	  }
126	  _ProcessKeyEvent(wParam, lParam, pfEaten);
127	  _UpdateComposition(pContext);
128	  if (*pfEaten)
129	    _fTestKeyUpPending = TRUE;
130	  return S_OK;
131	}
